   571→                  var folderId = idx === 0 ? null : ((data.pastas || [])[idx - 1] || {}).id || null;
   572→                  fetch('/api/criativos/historico/' + id + '/pasta', {
   573→                    method: 'PATCH',
   574→                    headers: { 'Content-Type': 'application/json' },
   575→                    body: JSON.stringify({ folder_id: folderId }),
   576→                  }).then(function () { carregarHistorico(); });
   577→                });
   578→            });
   579→          });
   580→        }
   581→        // Paginação
   582→        var total = data.total || 0;
   583→        var pages = data.pages || 1;
   584→        _setText('cri-pag-info', _histPage + ' / ' + pages);
